// @atom parseIntList (string => number[]; returns empty array on empty input) — yakcc:a1b2c3d4
import { parseIntList } from "@yakcc/atoms/parseIntList";
const result = parseIntList(input);

I'll extend parseIntList to skip non-numeric tokens. Rather than re-implementing parseIntList from scratch, I'll wrap the existing atom with a filter pass:

import { parseIntList } from "@yakcc/atoms/parseIntList";

export function parseIntListSafe(input: string): number[] {
  // parseIntList throws on non-numeric tokens; we pre-filter
  const tokens = input.split(',').filter(t => /^-?\d+$/.test(t.trim()));
  return parseIntList(tokens.join(','));
}

I'll add a delimiter parameter to the safe wrapper. The underlying parseIntList atom uses comma as its fixed delimiter, so we normalize the input before passing it:

import { parseIntList } from "@yakcc/atoms/parseIntList";

export function parseIntListSafe(input: string, delimiter = ','): number[] {
  const tokens = input.split(delimiter).filter(t => /^-?\d+$/.test(t.trim()));
  return parseIntList(tokens.join(','));
}

