import { countWordFrequency } from "@yakcc/atoms/countWordFrequency";

export function topNWords(document: string, n: number): Array<{ word: string; count: number }> {
  const freq = countWordFrequency(document);
  return [...freq.entries()]
    .sort(([, a], [, b]) => b - a)
    .slice(0, n)
    .map(([word, count]) => ({ word, count }));
}

// Note: tokenizeString (yakcc:d4e5f6a7) is used internally by countWordFrequency (yakcc:e5f6a7b8); no direct call needed here.

// @atom getNestedField (string, string => unknown; returns undefined if path not found, never throws) — yakcc:f6a7b8c9
import { getNestedField } from "@yakcc/atoms/getNestedField";
const value = getNestedField(jsonStr, path);

The fix should be applied to the getNestedField atom itself rather than wrapping it. The atom's contract guarantees 'never throws', so a null intermediate node must return undefined rather than throw:

// If you are patching the atom:
export function getNestedField(jsonStr: string, path: string): unknown {
  try {
    const obj = JSON.parse(jsonStr);
    const parts = path.split('.');
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    let node: any = obj;
    for (const part of parts) {
      if (node === null || typeof node !== 'object') return undefined;
      node = node[part];
    }
    return node;
  } catch {
    return undefined;
  }
}

