// @atom binarySearch (number[], number => number; returns -1 if not found, requires sorted input) — yakcc:a7b8c9d0
import { binarySearch } from "@yakcc/atoms/binarySearch";
const idx = binarySearch(arr, target);

The existing binarySearch atom (yakcc:a7b8c9d0) is typed for number arrays and uses numeric equality. For object arrays with a custom comparator you need a generalized version. I can create a new atom that wraps the core logic:

export function binarySearchBy<T>(arr: T[], target: T, comparator: (a: T, b: T) => number): number {
  let lo = 0;
  let hi = arr.length - 1;
  while (lo <= hi) {
    const mid = lo + Math.floor((hi - lo) / 2);
    const cmp = comparator(arr[mid]!, target);
    if (cmp === 0) return mid;
    if (cmp < 0) lo = mid + 1;
    else hi = mid - 1;
  }
  return -1;
}

// For the number case, binarySearch (yakcc:a7b8c9d0) remains the preferred atom.

