import { parsePaginationPage } from "@yakcc/atoms/parsePaginationPage";

export interface PaginationConfig {
  page: number;
  pageSize: number;
  offset: number;
}

export function buildPagination(pageParam?: string, pageSize = 20): PaginationConfig {
  const page = parsePaginationPage(pageParam);
  return { page, pageSize, offset: (page - 1) * pageSize };
}

import { sanitizeSqlLike } from "@yakcc/atoms/sanitizeSqlLike";
import { buildPagination } from './pagination';

export async function handleUserSearch(req: Request, db: Database): Promise<Response> {
  const query = req.query.q as string ?? '';
  const { page, pageSize, offset } = buildPagination(req.query.page as string | undefined);
  const safeQuery = sanitizeSqlLike(query);
  const results = await db.query(
    'SELECT * FROM users WHERE name LIKE ? LIMIT ? OFFSET ?',
    [`%${safeQuery}%`, pageSize, offset]
  );
  return Response.json({ results, page });
}

