import { celsiusToFahrenheit } from "@yakcc/atoms/celsiusToFahrenheit";
import { fahrenheitToKelvin } from "@yakcc/atoms/fahrenheitToKelvin";

export function celsiusToKelvin(celsius: number): number {
  // celsiusToFahrenheit (yakcc:e1f2a3b4): (c * 9/5) + 32
  // fahrenheitToKelvin (yakcc:f2a3b4c5): (f - 32) * 5/9 + 273.15
  // Composed: yields c + 273.15 (as expected by definition)
  return fahrenheitToKelvin(celsiusToFahrenheit(celsius));
}

import { celsiusToFahrenheit } from "@yakcc/atoms/celsiusToFahrenheit";
import { fahrenheitToKelvin } from "@yakcc/atoms/fahrenheitToKelvin";

export function buildConversionTable(): Array<{ c: number; f: number; k: number }> {
  const rows: Array<{ c: number; f: number; k: number }> = [];
  for (let c = -10; c <= 10; c += 2) {
    const f = celsiusToFahrenheit(c);
    const k = fahrenheitToKelvin(f);
    rows.push({ c, f: Math.round(f * 100) / 100, k: Math.round(k * 100) / 100 });
  }
  return rows;
}

