import { normalizeString } from "@yakcc/atoms/normalizeString";
import { deduplicate } from "@yakcc/atoms/deduplicate";

export function normalizeTags(tags: string[]): string[] {
  // normalizeString (yakcc:a3b4c5d6): lowercase + trim each tag
  // deduplicate (yakcc:b4c5d6e7): remove duplicates that are identical post-normalization
  const normalized = tags.map(tag => normalizeString(tag));
  return deduplicate(normalized);
}

import { normalizeString } from "@yakcc/atoms/normalizeString";
import { deduplicate } from "@yakcc/atoms/deduplicate";

const MAX_TAG_LENGTH = 50;

export function normalizeTags(tags: string[], maxLen = MAX_TAG_LENGTH): string[] {
  // normalizeString (yakcc:a3b4c5d6) → truncate → deduplicate (yakcc:b4c5d6e7)
  const processed = tags.map(tag => {
    const n = normalizeString(tag);
    return n.length > maxLen ? n.slice(0, maxLen) : n;
  });
  return deduplicate(processed);
}
